#include <bits/stdc++.h>
using namespace std;

const int N=5e4+10,INF=1e9;

struct Node{
    int mn,mx,lm,rm,tag;
    Node operator+(Node y){
        return {min(mn,y.mn),max(mx,y.mx),max(max(lm,y.lm),y.mx-mn),max(max(rm,y.rm),mx-y.mn),0};
    }
}t[N<<2];

struct Seg{
    int l,r;
}a[N],b[N];

int n,q,p[N];
int sz[N],f[N],dep[N],son[N],top[N],dfn[N],w[N],num,la,lb;
vector<int> g[N];

void dfs(int x,int fa){
    sz[x]=1;
    f[x]=fa,dep[x]=dep[fa]+1;
    for(int y:g[x])
        if(y!=fa){
            dfs(y,x);
            if(sz[y]>sz[son[x]])
                son[x]=y;
            sz[x]+=sz[y];
        }
}

void dfs(int x,int fa,int topx){
    top[x]=topx;
    dfn[x]=++num,w[num]=x;
    if(son[x])
        dfs(son[x],x,topx);
    for(int y:g[x])
        if(y!=fa && y!=son[x])
            dfs(y,x,y);
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]={p[w[l]],p[w[l]],0,0,0};
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void push_down(int cur,int l,int r){
    t[cur*2].mn+=t[cur].tag;
    t[cur*2].mx+=t[cur].tag;
    t[cur*2].tag+=t[cur].tag;
    t[cur*2+1].mn+=t[cur].tag;
    t[cur*2+1].mx+=t[cur].tag;
    t[cur*2+1].tag+=t[cur].tag;
    t[cur].tag=0;
}

void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        t[cur].mx+=k,t[cur].mn+=k;
        t[cur].tag+=k;
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=t[cur*2]+t[cur*2+1];
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(y<=mid)
        return query(cur*2,l,mid,x,y);
    if(x>mid)
        return query(cur*2+1,mid+1,r,x,y);
    return query(cur*2,l,mid,x,y)+query(cur*2+1,mid+1,r,x,y);
}

int solve(int x,int y,int w){
    la=0,lb=0;
    while(top[x]!=top[y]){
        if(dep[top[x]]>dep[top[y]])
            a[++la]={dfn[top[x]],dfn[x]},x=f[top[x]];
        else
            b[++lb]={dfn[top[y]],dfn[y]},y=f[top[y]];
    }
    //printf("%d %d\n",x,y);
    if(dep[x]<dep[y])
        b[++lb]={dfn[x],dfn[y]};
    else
        a[++la]={dfn[y],dfn[x]};
    Node ra={INF,-INF,-INF,-INF,0},rb={INF,-INF,-INF,-INF,0};
    for(int i=la;i;i--)
        ra=ra+query(1,1,n,a[i].l,a[i].r);
    for(int i=lb;i;i--)
        rb=rb+query(1,1,n,b[i].l,b[i].r);
    swap(ra.lm,ra.rm);
    /*
    printf("%d %d\n",b[1].l,b[1].r);
    printf("%d %d %d\n",ra.mn,ra.mx,ra.lm);
    printf("%d %d %d\n",rb.mn,rb.mx,rb.lm);
    */
    ra=ra+rb;
    for(int i=1;i<=la;i++)
        modify(1,1,n,a[i].l,a[i].r,w);
    for(int i=1;i<=lb;i++)
        modify(1,1,n,b[i].l,b[i].r,w);
    return max(0,ra.lm);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    dfs(1,0,1);
    build(1,1,n);
    scanf("%d",&q);
    while(q--){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        printf("%d\n",solve(u,v,w));
    }
    return 0;
}
